/*!40000 ALTER TABLE `recipes` DISABLE KEYS */;
INSERT INTO `recipes` VALUES (1,1,'Classic Margherita Pizza','A delicious Classic Margherita Pizza recipe.','Preheat your oven to its highest setting (usually 250┬░C/480┬░F).\nRoll out the pizza dough on a floured surface to your desired thickness.\nSpread a thin layer of tomato sauce over the base, leaving a crust at the edges.\nTear fresh mozzarella and basil evenly over the sauce.\nBake for 10-12 minutes until the crust is golden and cheese is bubbly.\nTop with fresh basil leaves before serving.',45,'https://images.unsplash.com/photo-1574071318508-1cdbab80d002',1,'2025-12-24 20:25:03','2025-12-24 20:25:03',2,600),(2,1,'Creamy Carbonara','A delicious Creamy Carbonara recipe.','Bring a large pot of salted water to a boil and cook spaghetti until al dente.\nWhile pasta cooks, fry pancetta in a pan until crisp and golden.\nIn a bowl, whisk eggs with grated Pecorino/Parmesan cheese and black pepper.\nDrain pasta, reserving some cooking water. Toss pasta directly into the pancetta pan.\nRemove from heat. Quickly mix in the egg mixture, adding pasta water to create a creamy sauce.\nServe immediately with extra black pepper.',20,'https://images.unsplash.com/photo-1612874742237-6526221588e3',1,'2025-12-24 20:25:03','2025-12-24 20:25:03',2,550),(3,1,'Mushroom Risotto','A delicious Mushroom Risotto recipe.','Saut├⌐ sliced mushrooms in butter/oil until browned; set aside.\nIn the same pan, toast Arborio rice for 1-2 minutes until translucent at edges.\nAdd warm broth one ladle at a time, stirring constantly until absorbed.\nContinue this process for about 20 minutes until rice is creamy but al dente.\nStir the mushrooms back in, add parmesan and butter, and serve warm.',40,'https://images.unsplash.com/photo-1476124369491-e7addf5db371',1,'2025-12-24 20:25:03','2025-12-24 20:25:03',4,500),(4,1,'Lasagna Classico','A delicious Lasagna Classico recipe.','Preheat oven to 180┬░C (350┬░F).\nSpread a thin layer of meat sauce on the bottom of a baking dish.\nLayer lasagna sheets, meat sauce, bechamel, and parmesan.\nRepeat layers until all ingredients are used, finishing with bechamel and cheese.\nBake for 40-45 minutes until golden brown and bubbly. Let rest for 10 mins before slicing.',90,'images/ingredients/Pizza Dough.jpg',1,'2025-12-24 20:25:03','2025-12-24 20:25:03',6,700),(5,1,'Caprese Salad','A delicious Caprese Salad recipe.','Slice fresh mozzarella and tomatoes into even rounds.\nOn a large platter, arrange tomato and cheese slices in an alternating pattern.\nTuck fresh basil leaves between the slices.\nDrizzle generously with extra virgin olive oil and balsamic glaze.\nSprinkle with sea salt and black pepper before serving.',10,'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcR9CP_rsUBdT0i1DrggRLkbq65cMbaMh-LT2g&s',1,'2025-12-24 20:25:03','2025-12-24 20:25:03',2,250),(6,1,'Sushi Roll Platter','A delicious Sushi Roll Platter recipe.','Rinse sushi rice until water runs clear, then cook according to package instructions.\nSeason cooked rice with sushi vinegar, sugar, and salt while fanning to cool.\nPlace a sheet of Nori on a bamboo mat and spread a thin layer of rice.\nArranged your choice of fish or vegetables in a line across the center.\nRoll the mat tightly away from you to form a cylinder.\nSlice into bite-sized pieces with a sharp wet knife.',60,'https://images.unsplash.com/photo-1579871494447-9811cf80d66c',2,'2025-12-24 20:25:03','2025-12-24 20:25:03',2,400),(7,1,'Spicy Ramen','A delicious Spicy Ramen recipe.','Bring chicken or pork broth to a simmer; add soy sauce, miso, and chili oil to taste.\nIn a separate pot, boil ramen noodles for 2-3 minutes until chewy; drain.\nSoft boil an egg (6-7 minutes), peel, and slice in half.\nPlace noodles in a bowl, pour over the hot broth.\nTop with egg, sliced green onions, nori, and sesame seeds.',30,'https://images.unsplash.com/photo-1569718212165-3a8278d5f624',2,'2025-12-24 20:25:03','2025-12-24 20:25:03',1,450),(8,1,'Chicken Pad Thai','A delicious Chicken Pad Thai recipe.','Soak rice noodles in warm water for 20 minutes until flexible.\nSear chicken pieces in a hot wok until cooked through; push to side.\nCrack an egg into the wok and scramble.\nAdd soaked noodles and tamarind sauce, tossing vigorously to coat.\nTop with crushed peanuts, bean sprouts, and a squeeze of lime.',25,'https://images.unsplash.com/photo-1559314809-0d155014e29e',2,'2025-12-24 20:25:03','2025-12-24 20:25:03',2,500),(9,1,'Beef Stir Fry','A delicious Beef Stir Fry recipe.','Slice beef against the grain into thin strips.\nHeat oil in a wok until smoking; sear beef batches for 1-2 mins.\nRemove beef, add broccoli and other veggies; stir-fry for 3-4 mins.\nReturn beef to the pan, add soy sauce, ginger, and garlic.\nToss everything together for 1 minute and serve over rice.',20,'https://images.unsplash.com/photo-1512058564366-18510be2db19',2,'2025-12-24 20:25:03','2025-12-24 20:25:03',2,400),(10,1,'Vietnamese Pho','A delicious Vietnamese Pho recipe.','Roast ginger and onion until charred; toast aromatic spices (anise, cloves).\nSimmer beef bones with charred aromatics for at least 3-4 hours.\nStrain broth and season with fish sauce and sugar.\nPlace cooked rice noodles and thin slices of raw beef in a bowl.\nPour boiling broth over the beef to cook it instantly. Garnish with fresh herbs.',120,'https://images.unsplash.com/photo-1582878826629-29b7ad1cdc43',2,'2025-12-24 20:25:03','2025-12-24 20:25:03',4,450),(11,1,'Street Tacos','A delicious Street Tacos recipe.','Marinate steak in citrus and spices provided in the ingredients.\nGrill meat over high heat until charred; let rest, then chop.\nWarm corn tortillas on a dry skillet until pliable.\nFill each tortilla with a generous amount of chopped meat.\nTop with diced white onion, fresh cilantro, salsa, and lime juice.',20,'https://images.unsplash.com/photo-1565299585323-38d6b0865b47',3,'2025-12-24 20:25:03','2025-12-24 20:25:03',3,400),(12,1,'Loaded Nachos','A delicious Loaded Nachos recipe.','Preheat oven to 200┬░C (400┬░F).\nSpread tortilla chips in a single layer on a baking sheet.\nGenerously sprinkle shredded cheese over the chips.\nAdd sliced jalapenos, black beans, or cooked beef if desired.\nBake for 5-7 minutes until cheese is fully melted. Serve with salsa and sour cream.',15,'https://images.unsplash.com/photo-1513456852971-30c0b8199d4d',3,'2025-12-24 20:25:03','2025-12-24 20:25:03',4,600),(13,1,'Chicken Quesadilla','A delicious Chicken Quesadilla recipe.','Place a large flour tortilla on a heated skillet.\nSprinkle half of the tortilla with shredded cheese and cooked chicken.\nFold the tortilla in half over the filling.\nCook for 2-3 minutes per side until golden brown and crispy.\nSlice into wedges and serve with guacamole or salsa.',10,'https://images.unsplash.com/photo-1618040996337-56904b7850b9',3,'2025-12-24 20:25:03','2025-12-24 20:25:03',2,500),(14,1,'Guacamole & Chips','A delicious Guacamole & Chips recipe.','Cut ripe avocados in half, remove pit, and scoop flesh into a bowl.\nMash with a fork to your desired consistency (chunky or smooth).\nSqueeze in juice of one fresh lime and season with salt.\nFold in diced onions, cilantro, and tomatoes if available.\nServe immediately with fresh tortilla chips.',10,'https://recipecontent.fooby.ch/11662_10-9_480-432@2x.jpg',3,'2025-12-24 20:25:03','2025-12-24 20:25:03',4,300),(15,1,'Royal Couscous','A delicious Royal Couscous recipe.','Prepare couscous by steaming or soaking in boiling water/stock with butter.\nIn a large pot, saut├⌐ onions, spices (cumin, turmeric), and root vegetables.\nAdd chickpeas, zucchini, and broth; simmer until vegetables are tender.\nFluff the couscous with a fork to remove any lumps.\nMound couscous on a platter and arrange the vegetable stew on top.',40,'images/ingredients/Couscous.jpg',4,'2025-12-24 20:25:03','2025-12-24 20:25:03',4,500),(16,1,'Falafel Wrap','A delicious Falafel Wrap recipe.','Deep fry or bake falafel balls until dark golden brown and crispy.\nWarm pita bread in a pan or oven until soft and pliable.\nLayer pita with hummus, lettuce, tomatoes, and cucumber.\nPlace 3 hot falafel balls in each pita gently smashing them.\nDrizzle generously with tahini sauce and roll up tight.',30,'images/ingredients/falafel.jpg',4,'2025-12-24 20:25:03','2025-12-24 20:25:03',2,450),(17,1,'Hummus Plate','A delicious Hummus Plate recipe.','Drain chickpeas (reserving liquid) and blend with tahini, lemon juice, and garlic.\nAdd cold water or aquafaba gradually while blending for fluffiness.\nSpoon onto a shallow plate, using a spoon to create swirls.\nTop with olive oil, paprika, parsley, and whole chickpeas.\nServe immediately with warm pita bread or veggie sticks.',10,'https://images.unsplash.com/photo-1637949385162-e416fb15b2ce',4,'2025-12-24 20:25:03','2025-12-24 20:25:03',2,300),(18,1,'Classic Cheeseburger','A delicious Classic Cheeseburger recipe.','Form beef into a patty slightly wider than your bun; season well with salt/pepper.\nGrill or fry on high heat for 3-4 minutes per side for medium.\nAdd cheese slice in the last minute of cooking; cover to melt.\nToast the bun until golden brown on the cut sides.\nAssemble burger with lettuce, tomato, pickles, and preferred condiments.',20,'https://images.unsplash.com/photo-1568901346375-23c9450c58cd',5,'2025-12-24 20:25:03','2025-12-24 20:25:03',1,700),(19,1,'Mac and Cheese','A delicious Mac and Cheese recipe.','Boil macaroni in plenty of salted water until al dente; drain.\nMelt butter in a pan, whisk in flour, then slowly add milk to make a b├⌐chamel.\nRemove sauce from heat and stir in grated cheddar until fully melted and smooth.\nCombine pasta with the cheese sauce, ensuring every noodle is coated.\nOptional: Top with breadcrumbs and bake for 15 minutes for a crispy crust.',30,'https://images.unsplash.com/photo-1543339308-43e59d6b73a6',5,'2025-12-24 20:25:03','2025-12-24 20:25:03',4,600),(20,1,'BBQ Ribs','A delicious BBQ Ribs recipe.','Remove membrane from ribs and coat thoroughly with dry spice rub.\nWrap in foil and bake low and slow at 150┬░C (300┬░F) for 2.5 - 3 hours.\nUnwrap ribs and brush generously with BBQ sauce.\nBroil or grill on high heat for 5-10 minutes to caramelize the sauce.\nLet rest for 10 minutes before slicing between the bones.',180,'https://www.southernliving.com/thmb/J02EQeOhOKHfmALt-jE_61idUck=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/oven-baked-baby-back-ribs-beauty-332-7deda00b7b4f4820a9c79f13ed09cfb9.jpg',5,'2025-12-24 20:25:03','2025-12-24 20:25:03',4,800),(21,1,'Grilled Cheese','A delicious Grilled Cheese recipe.','Butter one side of each slice of bread completely.\nPlace one slice butter-side down in a skillet over medium-low heat.\nAdd a generous amount of cheese and top with the second slice (butter-side up).\nCook until bottom is golden, then flip and cook the other side.\nSlice diagonally and serve hot while cheese is gooey.',10,'https://images.unsplash.com/photo-1528735602780-2552fd46c7af',5,'2025-12-24 20:25:03','2025-12-24 20:25:03',1,400),(22,1,'Caesar Salad','A delicious Caesar Salad recipe.','Wash and chop Romaine lettuce into bite-sized pieces; dry darker leaves.\nToss lettuce in a large bowl with Caesar dressing until evenly coated.\nAdd croutons and toss again gently.\nTop with plenty of shaved Parmesan cheese and fresh cracked black pepper.\nFor a protein boost, add sliced grilled chicken breast or shrimp.',15,'https://images.unsplash.com/photo-1550304943-4f24f54ddde9',5,'2025-12-24 20:25:03','2025-12-24 20:25:03',2,350),(23,1,'Fluffy Pancakes','A delicious Fluffy Pancakes recipe.','In a bowl, mix flour, sugar, baking powder, and a pinch of salt.\nIn another bowl, whisk milk, egg, and melted butter.\nCombine wet and dry ingredients gently; do not overmix (lumps are okay).\nPour batter onto a hot, buttered griddle.\nFlip when bubbles form on the surface; cook until golden brown.',20,'https://images.unsplash.com/photo-1567620905732-2d1ec7ab7445',6,'2025-12-24 20:25:03','2025-12-24 20:25:03',2,400),(24,1,'French Toast','A delicious French Toast recipe.','Whisk eggs, milk, cinnamon, and a splash of vanilla in a shallow dish.\nDip each slice of bread into the mixture, ensuring both sides are soaked.\nMelt butter in a pan over medium heat.\nFry bread for 2-3 minutes per side until golden and slightly crispy.\nServe immediately, dusted with powdered sugar and maple syrup.',15,'https://images.unsplash.com/photo-1484723091739-30a097e8f929',6,'2025-12-24 20:25:03','2025-12-24 20:25:03',2,450),(25,1,'Eggs Benedict','A delicious Eggs Benedict recipe.','Split and toast English muffins.\nPoach eggs in simmering water with vinegar for 3-4 minutes (soft yolk).\nCook Canadian bacon or ham in a skillet.\nPlace meat on muffin, top with poached egg.\nPour warm Hollandaise sauce over the top and garnish with chives.',30,'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcQE_9i1MYWwZ8WFSzg9H7JT0yYtTIeSVHWyoA&s',6,'2025-12-24 20:25:03','2025-12-24 20:25:03',2,500),(26,1,'Chocolate Lava Cake','A delicious Chocolate Lava Cake recipe.','Preheat oven to 200┬░C (400┬░F). Grease and flour ramekins.\nMelt chocolate and butter together in a double boiler or microwave.\nWhisk eggs and sugar until pale; fold into the chocolate mixture.\nStir in flour just until combined; pour batter into ramekins.\nBake for 12-14 minutesΓÇösides should be firm but center soft. Serve warm.',25,'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcQkD7OSbyvoEzYoqjoEAjzRxlV0QUXQ7E2M9g&s',7,'2025-12-24 20:25:03','2025-12-24 20:25:03',2,500),(27,1,'Strawberry Cheesecake','A delicious Strawberry Cheesecake recipe.','Crush biscuits and mix with melted butter; press into bottom of a springform pan.\nBeat cream cheese, sugar, and vanilla until smooth and creamy.\nPour filling over the crust and smooth the top with a spatula.\nRefrigerate for at least 4 hours or overnight until set.\nTop with fresh sliced strawberries and glaze before serving.',60,'https://images.unsplash.com/photo-1533134242443-d4fd215305ad',7,'2025-12-24 20:25:04','2025-12-24 20:25:04',8,450),(28,1,'Apple Pie','A delicious Apple Pie recipe.','Peel, core, and slice apples; toss with sugar and cinnamon.\nLine a pie dish with one crust; fill with the apple mixture.\nTop with the second crust, seal edges, and cut slits for steam to escape.\nBrush top with egg wash and sprinkle with sugar.\nBake at 190┬░C (375┬░F) for 45-50 minutes until golden and bubbling.',60,'images/ingredients/Pie Crust.jpg',7,'2025-12-24 20:25:04','2025-12-24 20:25:04',8,400),(29,1,'Tiramisu','A delicious Tiramisu recipe.','Brew strong espresso and let cool mixed with a splash of liqueur (optional).\nWhisk mascarpone with sugar and egg yolks until creamy.\nQuickly dip ladyfingers in coffee (don\'t soak) and layer in a dish.\nSpread half the mascarpone mixture over the fingers; repeat layers.\nDust top generously with cocoa powder and chill for 4 hours.',40,'images/ingredients/Tiramisu.jpg',7,'2025-12-24 20:25:04','2025-12-24 20:25:04',6,500),(30,1,'Quinoa Salad','A delicious Quinoa Salad recipe.','Rinse quinoa and cook in water/stock for 15 minutes; fluff and cool.\nDice cucumber, tomatoes, and red onion into small pieces.\nWhisk lemon juice, olive oil, salt, and pepper for the dressing.\nToss quinoa with veggies and dressing in a large bowl.\nGarnish with fresh parsley or mint and serve chilled.',20,'https://images.unsplash.com/photo-1623428187969-5da2dcea5ebf',8,'2025-12-24 20:25:04','2025-12-24 20:25:04',2,300),(31,1,'Green Smoothie Bowl','A delicious Green Smoothie Bowl recipe.','Freeze banana slices for at least 2 hours for a thick texture.\nBlend spinach, frozen banana, and a splash of almond milk until smooth.\nPour into a bowl; the consistency should be like soft-serve ice cream.\nTop with chia seeds, granola, fresh berries, and coconut flakes.\nServe immediately with a spoon.',10,'images/ingredients/GreenSmoothieBowl.jpeg',8,'2025-12-24 20:25:04','2025-12-24 20:25:04',1,250),(32,1,'Roasted Veggies','A delicious Roasted Veggies recipe.','Preheat oven to 200┬░C (400┬░F).\nWash and chop carrots, potatoes, and other root veggies into uniform chunks.\nToss veggies in a bowl with olive oil, rosemary, thyme, salt, and pepper.\nSpread in a single layer on a baking sheet; do not crowd.\nRoast for 35-40 minutes, tossing halfway, until golden and tender.',40,'https://images.unsplash.com/photo-1518843875459-f738682238a6',8,'2025-12-24 20:25:04','2025-12-24 20:25:04',4,200),(33,1,'Indian Butter Chicken','A delicious Indian Butter Chicken recipe.','Marinate chicken chunks in yogurt and spices for 1 hour.\nPan-fry chicken until browned but not fully cooked; set aside.\nIn the same pan, simmer tomato pur├⌐e with butter, cream, and fenugreek.\nReturn chicken to the sauce and simmer for 15 minutes.\nServe hot with naan bread or basmati rice.',50,'https://images.unsplash.com/photo-1588166524941-3bf61a9c41db',2,'2025-12-24 20:25:04','2025-12-24 20:25:04',4,600),(34,1,'Spanish Paella','A delicious Spanish Paella recipe.','Saut├⌐ onions, garlic, and peppers in a large paella pan.\nAdd rice and toast for a minute; stir in saffron infused broth.\nArrange seafood (shrimp, mussels) on top of the rice.\nSimmer without stirring until liquid is absorbed and a crust forms (socarrat).\nLet rest for 5 minutes before serving with lemon wedges.',60,'https://images.unsplash.com/photo-1534080564583-6be75777b70a',9,'2025-12-24 20:25:04','2025-12-24 20:25:04',6,550),(35,1,'Greek Gyros','A delicious Greek Gyros recipe.','Marinate meat with oregano, garlic, and lemon juice.\nGrill or pan-fry meat until cooked through and slightly charred.\nWarm pita breads lightly.\nSpread tzatziki on pita; top with meat, tomato, onion, and fries.\nWrap tightly in foil to hold everything together.',30,'https://images.unsplash.com/photo-1529006557810-274b9b2fc783',9,'2025-12-24 20:25:04','2025-12-24 20:25:04',2,500),(36,1,'French Onion Soup','A delicious French Onion Soup recipe.','Slice onions thinly and caramelize slowly in butter for 45 mins.\nAdd beef broth, thyme, and a splash of wine; simmer for 20 mins.\nLadle soup into oven-safe bowls.\nTop each bowl with a slice of toasted baguette and grated Gruy├¿re.\nBroil until cheese is bubbly and browned.',60,'https://images.unsplash.com/photo-1604152135912-04a022e23696?auto=format&fit=crop&w=400&q=80',9,'2025-12-24 20:25:04','2025-12-24 20:25:04',4,300),(37,1,'Fish and Chips','A delicious Fish and Chips recipe.','Heat oil in a deep fryer or large pot to 180┬░C (350┬░F).\nMake a beer batter with flour, baking powder, and cold beer.\nDip fish fillets into batter and carefully lower into hot oil.\nFry for 4-5 minutes until crisp and golden; drain on paper towels.\nFry potato strips twice for extra crispy chips. Serve with tartar sauce.',30,'images/ingredients/FishandChips.jpeg',9,'2025-12-24 20:25:04','2025-12-24 20:25:04',2,700),(38,1,'Ratatouille','A delicious Ratatouille recipe.','Spread a layer of piperade (pepper/tomato sauce) in a baking dish.\nSlice eggplant, zucchini, squash, and tomatoes into thin rounds.\nArrange vegetable slices in a spiral pattern over the sauce.\nDrizzle with olive oil and herbs de Provence; cover with parchment.\nBake at 150┬░C (300┬░F) for 45-60 mins. Serve warm or cold.',60,'https://images.unsplash.com/photo-1572453800999-e8d2d1589b7c',9,'2025-12-24 20:25:04','2025-12-24 20:25:04',4,250),(39,1,'Empanadas','A delicious Empanadas recipe.','Saut├⌐ beef mince with onions, cumin, paprika, and chopped green olives.\nRoll out pastry discs and place a spoonful of filling in the center.\nFold the dough over to create a half-moon shape; crimp edges with a fork.\nBrush with egg wash for a golden finish.\nBake at 200┬░C (400┬░F) for 20-25 minutes until puffed and golden brown.',60,'images/ingredients/Empanadas.jpg',10,'2025-12-24 20:25:04','2025-12-24 20:25:04',4,350),(40,1,'Ceviche','A delicious Ceviche recipe.','Cut fresh, high-quality white fish into small, even cubes.\nPlace fish in a glass bowl and cover completely with freshly squeezed lime juice.\nRefrigerate for 15-20 minutes until the fish turns opaque (\'cooks\').\nMix in finely diced red onion, chili peppers, and chopped cilantro.\nServe immediately with corn nuts or sweet potato slices.',20,'https://images.unsplash.com/photo-1535400255456-984241443b29',10,'2025-12-24 20:25:04','2025-12-24 20:25:04',2,200),(41,1,'Feijoada','A delicious Feijoada recipe.','Soak black beans overnight; drain and rinse.\nIn a large heavy pot, saut├⌐ bacon and onions until fragrant.\nAdd beans, pork cuts (sausage, ribs, loin), and water; simmer gently for 2-3 hours.\nCook until beans are creamy and meat is falling off the bone.\nServe over white rice with collard greens and orange slices.',180,'images/ingredients/Feijoada.jpg',10,'2025-12-24 20:25:04','2025-12-24 20:25:04',6,700),(42,1,'Arepas','A delicious Arepas recipe.','Mix pre-cooked corn flour (masharepa) with warm water and salt.\nKnead until smooth and let rest for 5 minutes.\nForm dough into patties about 1cm thick.\nCook on a lightly oiled griddle for 5-7 mins per side until crusty.\nSlice open hot arepas and stuff with butter and shredded cheese.',30,'images/ingredients/Arepas.jpg',10,'2025-12-24 20:25:04','2025-12-24 20:25:04',4,300),(43,1,'Jollof Rice','A delicious Jollof Rice recipe.','Blend tomatoes, scotch bonnet peppers, and onions into a smooth paste.\nFry the tomato mixture in oil with curry powder and thyme until reduced.\nStir in washed rice and chicken stock; cover tightly with foil and a lid.\nSimmer on low heat for 20-30 minutes so rice steams in the stew.\nFluff with a fork and serve with fried plantains.',60,'images/ingredients/Couscous.jpg',11,'2025-12-24 20:25:04','2025-12-24 20:25:04',4,450),(44,1,'Bunny Chow','A delicious Bunny Chow recipe.','Prepare a rich mutton or vegetable bean curry with aromatic spices.\nCut a loaf of unsliced white bread in half or quarters.\nHollow out the soft center (crumb), leaving the crust as a bowl.\nLadl hot curry into the bread bowl and top with the scooped-out bread.\nGarnish with coriander and eat with your hands.',45,'https://images.unsplash.com/photo-1596797038530-2c107229654b?auto=format&fit=crop&w=600&q=80',11,'2025-12-24 20:25:04','2025-12-24 20:25:04',2,600),(45,1,'Shakshuka','A delicious Shakshuka recipe.','Saut├⌐ onions, bell peppers, and garlic in a skillet until soft.\nPour in canned tomatoes, cumin, paprika, and chili flakes; simmer for 10 mins.\nMake small wells in the sauce with a spoon and crack eggs into them.\nCover pan and cook until whites are set but yolks are runny.\nSprinkle with feta cheese and parsley; serve with crusty bread.',30,'https://images.unsplash.com/photo-1590412200988-a436970781fa',11,'2025-12-24 20:25:04','2025-12-24 20:25:04',2,350),(46,1,'Tagine','A delicious Tagine recipe.','Brown chicken pieces in a tagine or heavy pot.\nAdd onions, ginger, cinnamon, saffron, and stock.\nStir in dried apricots and almonds; cover and simmer low for 45 mins.\nCook until chicken is tender and sauce has thickened.\nServe hot over fluffy couscous, garnished with fresh cilantro.',90,'images/ingredients/Tagine.jpg',11,'2025-12-24 20:25:04','2025-12-24 20:25:04',4,500),(47,1,'Pierogi','A delicious Pierogi recipe.','Make a simple dough with flour, water, egg, and salt; let rest.\nPrepare filling by mashing boiled potatoes with cheese and fried onions.\nRoll dough thin and cut circles; place filling in center and fold to seal.\nBoil in salted water until they float to the surface.\nSear in a pan with butter and serve with sour cream.',60,'https://img.mesrecettesfaciles.fr/2023-06/pierogi-xny-1200.webp',9,'2025-12-24 20:25:04','2025-12-24 20:25:04',4,400),(48,1,'Borsch','A delicious Borsch recipe.','Simmer beef to create a rich broth; skim foam.\nAdd diced potatoes and shredded cabbage to the broth.\nSaut├⌐ grated beets, carrots, and onions with tomato paste separately.\nSpecifically add saut├⌐ed veggies to the pot and cook until tender.\nFinish with fresh dill, garlic, and a dollop of sour cream when serving.',90,'images/ingredients/Tagine.jpg',9,'2025-12-24 20:25:04','2025-12-24 20:25:04',6,250),(49,1,'Goulash','A delicious Goulash recipe.','Fry chopped onions in lard or oil until golden.\nAdd cubed beef and brown on all sides; remove from heat to stir in paprika.\nAdd water/stock, caraway seeds, and simmer covered for 1.5 - 2 hours.\nAdd cubed carrots and potatoes in the last 30 minutes.\nServe the thick stew with bread or dumplings.',120,'https://images.unsplash.com/photo-1604908176997-125f25cc6f3d',9,'2025-12-24 20:25:04','2025-12-24 20:25:04',4,500),(50,1,'Bubble Tea','A delicious Bubble Tea recipe.','Boil tapioca pearls for 20 mins until chewy; soak in sugar syrup.\nBrew strong black tea and let it cool completely.\nPour pearls and syrup into a glass.\nAdd ice cubes and pour tea over the ice.\nTop with milk or cream and insert a wide straw.',15,'https://images.unsplash.com/photo-1558160074-4d7d8bdf4256',2,'2025-12-24 20:25:04','2025-12-24 20:25:04',1,300),(51,1,'Churros','A delicious Churros recipe.','Boil water, butter, and sugar; stir in flour to make a dough.\nLet dough cool slightly, then beat in eggs one by one.\nPipe strips of dough into hot oil using a star nozzle.\nFry until golden brown and drain on paper towels.\nRoll warm churros in cinnamon sugar mix.',30,'images/ingredients/Churros.jpg',7,'2025-12-24 20:25:04','2025-12-24 20:25:04',4,450),(52,1,'Belgian Waffles','A delicious Belgian Waffles recipe.','Mix flour, yeast, milk, and eggs to form a sticky dough.\nLet dough rise in a warm place for 30 minutes.\nFold in pearl sugar chunks right before cooking.\nScoop dough onto a hot waffle iron.\nCook until caramelized and crispy.',20,'https://images.unsplash.com/photo-1562376552-0d160a2f238d',7,'2025-12-24 20:25:04','2025-12-24 20:25:04',2,500),(53,1,'Mango Sticky Rice','A delicious Mango Sticky Rice recipe.','Soak glutinous rice, then steam for 20 minutes.\nSimmer coconut milk with sugar and salt; mix half into cooked rice.\nLet rice sit for 10 minutes to absorb liquid.\nSlice ripe sweet mango.\nServe rice topped with remaining coconut sauce and mango slices.',40,'https://images.unsplash.com/photo-1579954115545-a95591f28bfc',2,'2025-12-24 20:25:04','2025-12-24 20:25:04',2,400),(54,1,'Spring Rolls','A delicious Spring Rolls recipe.','Cook shrimp and vermicelli noodles; let cool.\nDip rice paper wrapper briefly in warm water to soften.\nLay herbs, shrimp, and noodles in the center of the wrapper.\nFold sides in and roll tightly into a cylinder.\nServe fresh with hoisin or peanut dipping sauce.',40,'images/ingredients/SpringRolls.jpg',2,'2025-12-24 20:25:04','2025-12-24 20:25:04',4,300),(55,1,'Kebab','A delicious Kebab recipe.','Mix lamb mince with garlic, cumin, coriander, and chili.\nKnead mixture well until sticky.\nMold handfuls of meat onto skewers in a long sausage shape.\nGrill over charcoal or in a pan, turning often.\nServe with flatbread, yogurt, and pickled onions.',30,'https://images.unsplash.com/photo-1555939594-58d7cb561ad1',4,'2025-12-24 20:25:04','2025-12-24 20:25:04',2,500),(56,1,'Miso Soup','A delicious Miso Soup recipe.','Bring dashi stock to a gentle simmer (do not boil hard).\nAdd cubed tofu and rehydrated wakame seaweed.\nPlace miso paste in a ladle and dissolve with some hot broth.\nStir dissolved miso back into the soup and remove from heat immediately.\nGarnish with sliced green onions.',10,'https://images.unsplash.com/photo-1598514982205-f36b96d1e8d4',2,'2025-12-24 20:25:04','2025-12-24 20:25:04',2,100),(57,1,'Garlic Bread','A delicious Garlic Bread recipe.','Preheat oven to 180┬░C (350┬░F).\nMix softened butter with minced garlic and parsley.\nSlice baguette diagonally almost all the way through.\nSpread garlic butter generously between each slice.\nWrap in foil and bake for 10-15 minutes until crispy.',15,'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRTrIDSrMqdEAzQbW7htOG5EYPrYmuYXQTXhw&s',1,'2025-12-24 20:25:04','2025-12-24 20:25:04',4,300),(59,2,'Tanjia','Marrakech\'s Tanjia','Put the meat into a large bowl. Add garlic, spices, salt, olive oil, and smen. Mix well so the meat is evenly coated.\r\nCut the preserved lemon into pieces and add it to the mixture. This gives tanjia its classic flavor.\r\nTraditionally, tanjia is cooked in a clay pot called a tanjia. If you donΓÇÖt have one, use a heavy oven-safe pot with a lid\r\nPour in the waterΓÇöjust enough to keep the meat moist, not soupy.\r\nThe pot is sealed with parchment and string and placed in hot ashes at a hammam for several hours\r\nOR: Cover tightly and cook in the oven at 150┬░C (300┬░F) for 4ΓÇô5 hours until the meat is very tender.\r\nThe meat should be soft and juicy, almost falling apart. Serve hot with Moroccan bread (khobz).',300,'https://api2.arabesquekitchen.com/images/recipe-tanjia-marrakchia-image-caafx/recipe-tanjia-marrakchia-image-caafx-optimized.webp?version=1683101096422',4,'2025-12-25 00:38:25','2025-12-25 00:38:25',4,500),(61,1,'Pan-Seared Scallops with Pesto Cream Sauce and Garlic Shrimp','An AI generated surprise recipe! Enjoy this creative Dinner.','Rinse the scallops and pat them dry with a paper towel\nSeason the scallops with salt and black pepper\nHeat 2 tablespoons of butter in a large skillet over medium-high heat\nSear the scallops for 2-3 minutes on each side, or until they are golden brown\nRemove the scallops from the skillet and set them aside\nAdd the remaining 2 tablespoons of butter to the skillet\nAdd the garlic to the skillet and saut├⌐ for 1 minute, or until fragrant\nAdd the shrimp to the skillet and saut├⌐ for 2-3 minutes on each side, or until they are pink and cooked through\nRemove the shrimp from the skillet and set them aside with the scallops\nAdd the pesto to the skillet and stir to combine with the garlic and butter\nPour in the heavy cream and stir to combine with the pesto mixture\nBring the cream sauce to a simmer and let cook for 2-3 minutes, or until it has thickened slightly\nStir in the chopped parsley and season the sauce with salt and black pepper to taste\nReturn the scallops and shrimp to the skillet and toss them in the cream sauce to coat\nServe the scallops and shrimp hot, with lemon wedges on the side\nGarnish with additional parsley if desired',45,'https://www.simplyrecipes.com/thmb/YB9K4C3uqF8X6F1VY9Y9Y1T6zXU=/1500x0/filters:no_upscale():max_bytes(150000):strip_exif()/Simply-Recipes-Pan-Seared-Scallops-LEAD-09-4x3-43c64f5a45d74d808bac6a6f7e5041d7.jpg',1,'2026-04-26 21:04:18','2026-04-26 21:04:18',2,550),(62,1,'Pan-Seared Scallops with Lemon Garlic Shrimp and Pesto Fettuccine','An AI generated surprise recipe! Enjoy this creative Dinner.','Bring a large pot of salted water to a boil\nAdd the fettuccine pasta to the boiling water and cook until al dente\nReserve 1 cup of pasta water before draining the fettuccine\nIn a large skillet, melt 1 tablespoon of butter over medium heat\nAdd the garlic to the skillet and saut├⌐ for 1 minute until fragrant\nAdd the shrimp to the skillet and saut├⌐ for 2-3 minutes per side until pink and cooked through\nRemove the shrimp from the skillet and set aside\nAdd the remaining 1 tablespoon of butter to the skillet\nAdd the scallops to the skillet and sear for 2-3 minutes per side until golden brown and cooked through\nRemove the scallops from the skillet and set aside with the shrimp\nAdd the pesto sauce to the skillet and stir to combine with the garlic and butter\nAdd the reserved pasta water to the skillet in small increments to achieve a creamy pesto sauce\nAdd the cooked fettuccine pasta to the skillet and toss to combine with the pesto sauce\nStir in the lemon juice and season with salt and black pepper to taste\nReturn the shrimp and scallops to the skillet and toss to combine with the pasta and pesto sauce\nGarnish with fresh parsley and serve immediately',45,'https://www.simplyrecipes.com/thmb/zW4Z2O9xL8Vw0Kb2u1gU0Vz4PzI=/1500x0/fettuccine-with-shrimp-and-scallops-7-4e7074f5e1c34a108a3cd1f2ac8b9b5f.jpg',1,'2026-04-26 21:04:40','2026-04-26 21:04:40',2,550),(64,1,'Pan-Seared Scallops with Pesto Cream Sauce and Garlic Mashed Potatoes','An AI generated surprise recipe! Enjoy this creative Dinner.','Rinse the scallops under cold water and pat them dry with paper towels\nSeason the scallops with salt and black pepper\nHeat 2 tablespoons of olive oil in a large skillet over medium-high heat\nAdd the scallops to the skillet and sear for 2-3 minutes on each side\nRemove the scallops from the skillet and set them aside on a plate\nIn a food processor, combine the basil, parsley, garlic, and pine nuts\nProcess the mixture until it is well combined and slightly smooth\nAdd the Grana Padano cheese to the food processor and process until well combined\nWith the food processor running, slowly pour in the olive oil through the top\nProcess the mixture until it is smooth and creamy\nAdd the heavy cream to the food processor and process until well combined\nBring a large pot of salted water to a boil\nPeel and chop the potatoes into 1-inch cubes\nAdd the potatoes to the boiling water and cook until they are tender\nDrain the potatoes and return them to the pot\nAdd the unsalted butter, salt, and black pepper to the potatoes\nMash the potatoes with a potato masher or a fork until they are smooth and creamy\nAdd the pesto cream sauce to the skillet used for the scallops and heat it over medium heat\nSimmer the sauce for 2-3 minutes or until it is heated through\nTo serve, place a scoop of the mashed potatoes on a plate, top with a scallop, and spoon some of the pesto cream sauce over the top',45,'https://www.simplyrecipes.com/thmb/GyJ1Q4pZjzR1K4j9q4kN1k4xQzI=/1500x0/filters:no_upscale():max_bytes(150000):strip_exif()/summer-pesto-sauce-9ac6f521a64449b5a6d5fc4c2c17c1d8.jpg',1,'2026-04-26 21:05:23','2026-04-26 21:05:23',2,550),(65,1,'Grilled Octopus with Spicy Mango Salsa and Coconut Rice','An AI generated surprise recipe! Enjoy this creative Dinner.','Rinse the octopus under cold water, then cut it into 1-inch pieces.\nIn a large bowl, whisk together 1 tablespoon of olive oil, 1 clove of minced garlic, and 1/2 teaspoon of grated ginger.\nAdd the octopus pieces to the bowl and toss to coat with the marinade.\nCover the bowl with plastic wrap and refrigerate for at least 30 minutes.\nPreheat a grill or grill pan to medium-high heat.\nRemove the octopus from the marinade, letting any excess liquid drip off.\nGrill the octopus for 2-3 minutes per side, or until it\'s charred and cooked through.\nTransfer the grilled octopus to a plate and cover with foil to keep warm.\nCut the mango into small dice and place it in a bowl.\nCut the red onion into small dice and add it to the bowl with the mango.\nSeed and finely chop the jalape├▒o pepper, then add it to the bowl.\nChop the cilantro and add it to the bowl.\nSqueeze the lime juice over the mango mixture and toss to coat.\nIn a medium saucepan, combine the coconut milk, uncooked rice, and 1 cup of water.\nBring the coconut milk mixture to a boil, then reduce the heat to low, cover, and simmer for 15-20 minutes, or until the liquid is absorbed and the rice is tender.\nFluff the coconut rice with a fork and season with salt and black pepper to taste.\nTo serve, divide the coconut rice onto plates, then top with the grilled octopus and spicy mango salsa.\nGarnish with additional cilantro and lime wedges, if desired.',45,'https://www.simplyrecipes.com/thmb/hV4Q8qf6VWQYz0h9K9y9Y8Vz4dE=/1500x0/filters:no_upscale():max_bytes(150000):strip_exif()/grilled-octopus-9-ac9d45a55c914a6f9a8fc9b6eeea85af.jpg',1,'2026-04-26 21:08:41','2026-04-26 21:08:41',4,520),(66,1,'Peruvian Grilled Octopus with Aji Amarillo Sauce and Cilantro Lime Rice','An AI generated surprise recipe! Enjoy this creative Dinner.','Preheat the grill to medium-high heat.\nRinse the octopus under cold water, then pat it dry with paper towels.\nCut the octopus into 1-inch pieces and season with salt and black pepper.\nIn a blender or food processor, combine aji amarillo peppers, garlic, and ginger, and blend until smooth.\nHeat the olive oil in a saucepan over medium heat, then add the blended pepper mixture and cook for 2-3 minutes.\nAdd the lime juice to the saucepan and stir to combine.\nBring the sauce to a simmer and cook for 5-7 minutes or until it thickens slightly.\n Grill the octopus for 2-3 minutes per side or until it\'s slightly charred and cooked through.\nIn a medium saucepan, melt 1 tablespoon of butter over medium heat.\nAdd the chopped cilantro to the saucepan and cook for 1 minute, stirring constantly.\nAdd the uncooked white rice to the saucepan and cook for 1-2 minutes, stirring constantly.\nAdd the water to the saucepan and bring to a boil.\nReduce the heat to low, cover, and simmer for 15-20 minutes or until the rice is cooked and fluffy.\nFluff the cooked rice with a fork and stir in the remaining 1 tablespoon of butter.\nTo serve, place the grilled octopus on a plate, spoon the aji amarillo sauce over the top, and serve with the cilantro lime rice.',45,'https://www.perudelights.com/wp-content/uploads/2020/07/octopus-aji-amarillo-sauce.jpg',1,'2026-04-26 21:09:23','2026-04-26 21:09:23',4,550),(67,1,'Peruvian Grilled Mahi Mahi with Aji Amarillo Sauce and Saffron Rice','An AI generated surprise recipe! Enjoy this creative Dinner.','Preheat the grill to medium-high heat\nRinse the Mahi Mahi fillets under cold water and pat them dry with a paper towel\nIn a blender, puree the Aji Amarillo peppers, olive oil, lime juice, garlic, and ginger to make the sauce\nStrain the sauce through a fine-mesh sieve into a bowl to remove the pepper seeds and skin\nSeason the Mahi Mahi fillets with salt and black pepper on both sides\nGrill the Mahi Mahi for 4-5 minutes per side, or until it reaches an internal temperature of 145┬░F\nWhile the fish is grilling, heat the chicken broth in a saucepan over medium heat\nAdd the saffron threads to the chicken broth and let it steep for 5 minutes\nAdd the uncooked white rice to the saucepan and stir to combine with the saffron-infused broth\nBring the rice mixture to a boil, then reduce the heat to low, cover, and simmer for 15-20 minutes, or until the rice is tender\nFluff the cooked rice with a fork and season with salt to taste\nTo serve, place a grilled Mahi Mahi fillet on each plate, spoon the Aji Amarillo sauce over the top, and serve with a side of saffron rice\nGarnish with chopped fresh cilantro and serve immediately',45,'https://www.peru.org/images/recipes/mahimahi-aji-amarillo.jpg',1,'2026-04-26 21:12:41','2026-04-26 21:12:41',4,550),(68,1,'Pan-Seared Saffron Crusted Octopus with Spicy Mango Salsa and Coconut Rice','An AI generated surprise recipe! Enjoy this creative Dinner.','Rinse the octopus under cold water and pat it dry with paper towels\nIn a small bowl, mix together saffron threads, paprika, garlic powder, salt, and black pepper\nRub the spice mixture all over the octopus, making sure to coat it evenly\nHeat 1 tablespoon of olive oil in a large skillet over medium-high heat\nSear the octopus for 2-3 minutes on each side, or until it\'s nicely browned\nRemove the octopus from the skillet and set it aside to rest\nPeel and dice the mango into small pieces\nFinely chop the red onion and jalape├▒o pepper\nIn a medium bowl, combine the diced mango, chopped red onion, and jalape├▒o pepper\nStir in chopped cilantro and lime juice\nIn a large saucepan, heat the remaining 1 tablespoon of olive oil over medium heat\nAdd the uncooked rice to the saucepan and stir to coat the rice with oil\nAdd the coconut milk and water to the saucepan, and bring to a boil\nReduce the heat to low, cover the saucepan with a tight-fitting lid, and simmer for 15-20 minutes, or until the rice is cooked and fluffy\nSlice the rested octopus into bite-sized pieces\nServe the octopus on top of the coconut rice, with the spicy mango salsa spooned over the top\nGarnish with additional cilantro and lime wedges, if desired',45,'https://upload.wikimedia.org/wikipedia/commons/thumb/5/5d/Octopus_with_saffron_rice_and_vegetables.jpg/800px-Octopus_with_saffron_rice_and_vegetables.jpg',1,'2026-04-26 21:14:17','2026-04-26 21:14:17',4,550),(69,1,'Korean-Style Pan-Seared Tuna with Gochujang Glaze and Pineapple Salsa','An AI generated surprise recipe! Enjoy this creative Dinner.','Preheat a skillet or grill pan over medium-high heat\nIn a small bowl, whisk together gochujang paste, soy sauce, brown sugar, rice vinegar, garlic, and ginger to make the glaze\nSeason the tuna steaks with salt and black pepper\nAdd sesame oil to the preheated skillet and sear the tuna steaks for 2-3 minutes per side\nTransfer the tuna steaks to a plate and brush the gochujang glaze over them\nLet the tuna rest for a few minutes before slicing\nIn a separate bowl, combine pineapple, red onion, cilantro, and lime juice to make the salsa\nSeason the salsa with salt to taste\nTo serve, slice the tuna steaks and place them on a plate\nSpoon the pineapple salsa over the tuna\nGarnish with additional cilantro and serve immediately\nServe with steamed vegetables or a side of kimchi for a complete meal\nStore any leftovers in an airtight container in the refrigerator for up to 2 days',45,'https://www.simplyrecipes.com/thmb/Gg4VdL1g1VW3u0Yz4cWp5xV3KwK=/1500x0/filters:no_upscale():max_bytes(150000):strip_exif()/korean-tuna-16-56f5dc9c5f9b5829b77f54a35e55f364.jpg',3,'2026-04-26 21:35:49','2026-04-26 21:35:49',4,550),(70,1,'Peruvian Grilled Shrimp Anticuchos with Aji Amarillo Sauce','An AI generated surprise recipe! Enjoy this creative Dinner.','Peel and de-vein the shrimp, then set them aside in a bowl of cold water.\nRoast the Aji Amarillo peppers over an open flame or in the oven at 400┬░F for about 10 minutes, until charred.\nOnce the peppers are cool enough, peel off the skin, remove the seeds, and place them in a blender.\nAdd the red onion, garlic, cilantro, lime juice, salt, and black pepper to the blender with the peppers.\nBlend the mixture until smooth, then heat the vegetable oil in a saucepan over medium heat.\nPour the blended pepper mixture into the saucepan and simmer for about 10 minutes, stirring occasionally.\nThread the shrimp onto the wooden skewers, leaving a little space between each shrimp.\nBrush the shrimp with the Aji Amarillo sauce and season with additional salt and black pepper if needed.\nPreheat a grill to medium-high heat and grill the shrimp anticuchos for about 2-3 minutes per side, until pink and cooked through.\nWhile the shrimp are grilling, toast some crusty bread and crumble the Queso Fresco over it.\nTo serve, place the grilled shrimp anticuchos on top of the toasted bread, spoon some of the Aji Amarillo sauce over them, and sprinkle with additional cilantro if desired.\nServe immediately and enjoy the combination of flavors and textures.\nFor an added touch, serve with a side of grilled corn or sweet potato.',45,'https://www.peruvianfood.com/wp-content/uploads/2019/06/Anticuchos.jpg',1,'2026-04-26 21:38:11','2026-04-26 21:38:11',4,550),(71,1,'Korean-Style Grilled Pineapple with Spicy Tofu and Kimchi Fried Rice','An AI generated surprise recipe! Enjoy this creative Dinner.','Preheat the grill to medium-high heat.\nCut the tofu into bite-sized cubes and place it in a bowl.\nIn a small bowl, whisk together sesame oil, gochujang, soy sauce, brown sugar, and crushed red pepper.\nPour the marinade over the tofu and toss to coat.\nLet the tofu marinate for at least 10 minutes.\nCut the pineapple into wedges and brush with a little sesame oil.\nGrill the pineapple for 2-3 minutes per side, or until caramelized.\nGrill the tofu for 3-4 minutes per side, or until golden brown.\nHeat 1 tablespoon of sesame oil in a large skillet over medium-high heat.\nAdd the kimchi to the skillet and cook for 2-3 minutes, or until slightly caramelized.\nAdd the cooked white rice to the skillet and stir-fry for 5 minutes, breaking up any clumps with a spatula.\nAdd the cooked tofu, green onions, and a pinch of soy sauce to the skillet and stir-fry for another minute.\nTo serve, place a portion of the kimchi fried rice on a plate, top with a grilled pineapple wedge and a few pieces of the spicy tofu.\nGarnish with additional green onions and serve immediately.',45,'https://source.unsplash.com/800x600/?korean-grilled-pineapple-tofu-kimchi-fried-rice',7,'2026-04-26 21:39:45','2026-04-26 21:39:45',2,550),(72,1,'Korean-Style Grilled Pineapple and Shrimp Skewers with Spicy Gochujang Sauce','An AI generated surprise recipe! Enjoy this creative Dinner.','Preheat the grill to medium-high heat.\nThread the shrimp, pineapple chunks, and a few green onion pieces onto metal or bamboo skewers.\nIn a large bowl, whisk together gochujang sauce, sesame oil, brown sugar, garlic, and ginger to make the marinade.\nPlace the skewers in the marinade, turning to coat evenly, and let it sit for at least 15 minutes, or up to 30 minutes in the refrigerator.\nRemove the skewers from the marinade, letting any excess liquid drip off.\nGrill the skewers for 8-10 minutes, turning occasionally, until the shrimp are pink and cooked through.\nWhile the skewers are grilling, prepare the spicy gochujang sauce for serving by mixing an additional 2 tablespoons of gochujang sauce with 1 tablespoon of water in a small bowl.\nOnce the skewers are cooked, brush them with the spicy gochujang sauce during the last minute of grilling.\nSprinkle the sesame seeds over the skewers during the last 30 seconds of grilling.\nRemove the skewers from the grill and garnish with additional green onions and sesame seeds if desired.\nServe the skewers hot with the spicy gochujang sauce on the side for dipping.\nConsider serving with steamed rice or noodles to soak up the flavorful sauce.',45,'https://source.unsplash.com/800x600/?shrimp-skewers-pineapple',9,'2026-04-26 22:39:41','2026-04-26 22:39:41',4,550),(73,1,'Korean-Style Grilled Octopus with Mango Salsa','An AI generated surprise recipe! Enjoy this creative Dinner.','Preheat the grill to medium-high heat.\nRinse the octopus under cold water, then pat it dry with paper towels.\nCut the octopus into large pieces, if desired, for easier grilling.\nIn a large bowl, whisk together gochujang, sesame oil, salt, and black pepper to make the marinade.\nAdd the octopus pieces to the marinade and toss to coat evenly.\nLet the octopus marinate for at least 20 minutes, or up to 30 minutes in the refrigerator.\nWhile the octopus is marinating, prepare the mango salsa by dicing the mango and red onion.\nChop the cilantro and add it to the mango and red onion mixture.\nSqueeze the lime juice over the salsa mixture and toss to combine.\nSeason the salsa with salt to taste.\nRemove the octopus from the marinade, letting any excess liquid drip off.\nGrill the octopus for 2-3 minutes per side, or until it\'s cooked through and slightly charred.\nTransfer the grilled octopus to a plate and serve with the mango salsa spooned over the top.\nGarnish with additional cilantro, if desired.\nServe immediately and enjoy!',45,'https://source.unsplash.com/800x600/?korean-grilled-octopus',10,'2026-04-26 23:27:38','2026-04-26 23:27:38',2,420);
